import { useEffect, useState} from "react";
import axios from "axios";

import CourseCard from "../Components/CourseCard";
import config from "../config.json"


function MainPage() {
  const [courses, setCourses] = useState([]);
  const [error, setError] = useState();

 /* useEffect(() => {
    fetch(`/Files/Tests/UserCoursesTest.json`, { cache: "no-store" })
      .then(res => {
        if (!res.ok) throw new Error("Ничего не найдено");
        return res.json();
      }).then(datas => setCourses(datas))
  }, []);*/
  useEffect(() => {
    axios
      .get(config.BaseURL+"/courses")
      .then(res => setCourses(res.data))
      .catch(() => setError("Ошибка запроса"));

    console.log(error);
    if(courses != []){ 
      console.log(courses);
    }
  }, []);

  return (
    <div className="main-page">
      
      <div className="lesson-filter-container">
        <div className="filter">
          <h4>Сортировать по</h4>
          <select id="group--1" style={{ padding: "8px" }}>
            <option>Дата создания</option>
            <option>Количество покупок</option>
            <option>Рейтинг</option>
          </select>
        </div>

        <div className="lessons">
          <ul>
            {courses.map((item,index)=>(
              <li>
                <CourseCard key={index} courseInfo={item}/>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
}

export default MainPage;
